"""
Auto-generates SDK setting classes from settings.json.

Usage:
    uv run python scripts/generate_settings.py <path-to-settings.json>          # Generate all files
    uv run python scripts/generate_settings.py <path-to-settings.json> --check  # Verify files are up-to-date
"""
from __future__ import annotations

import json
import sys
from pathlib import Path
from typing import Any

REPO_ROOT = Path(__file__).resolve().parent.parent
SETTINGS_DIR = REPO_ROOT / "src" / "rapidata" / "rapidata_client" / "settings"

GENERATED_HEADER = (
    "# This file is auto-generated by scripts/generate_settings.py\n"
    "# Do not edit manually. Changes will be overwritten.\n"
    "# To modify, update settings.json and re-run the generator.\n"
)

HANDWRITTEN_FILES = {
    "_rapidata_setting.py",
    "custom_setting.py",
}


def load_settings(settings_json: Path) -> list[dict[str, Any]]:
    with open(settings_json) as f:
        data = json.load(f)
    return data["settings"]


def generate_setting_module(s: dict[str, Any]) -> str:
    lines: list[str] = []
    lines.append(GENERATED_HEADER)
    lines.append("from __future__ import annotations\n")

    has_warnings = s.get("warnings") is not None

    lines.append(
        "from rapidata.rapidata_client.settings._rapidata_setting import RapidataSetting"
    )

    if has_warnings:
        lines.append(
            "from rapidata.rapidata_client.config import managed_print"
        )

    lines.append("")
    lines.append("")

    # Main class
    class_name = s["class_name"]
    param_name = s["param_name"]
    value_type = s["type"]
    default = s.get("default")
    description = s["description"]
    param_description = s["param_description"]

    lines.append(f"class {class_name}(RapidataSetting):")
    lines.append(f'    """')
    for desc_line in description.split("\n"):
        if desc_line.strip():
            lines.append(f"    {desc_line}")
        else:
            lines.append("")
    lines.append("")
    lines.append("    Args:")

    # Build type annotation string for docstring
    type_str = value_type  # "bool" or "int"
    if default is not None:
        lines.append(
            f"        {param_name} ({type_str}, optional): {param_description}"
        )
    else:
        lines.append(
            f"        {param_name} ({type_str}): {param_description}"
        )

    lines.append('    """')
    lines.append("")

    # __init__ signature
    if default is not None:
        if value_type == "bool":
            default_str = "True" if default else "False"
        else:
            default_str = str(default)
        lines.append(
            f"    def __init__(self, {param_name}: {type_str} = {default_str}):"
        )
    else:
        lines.append(f"    def __init__(self, {param_name}: {type_str}):")

    # Validation
    if value_type == "bool":
        lines.append(f"        if not isinstance({param_name}, bool):")
        lines.append(
            f'            raise ValueError("The value must be a boolean.")'
        )

    validation = s.get("validation")
    if validation:
        if "min" in validation and validation["min"] is not None:
            min_val = validation["min"]
            min_err = validation.get(
                "min_error", f"The value must be greater than or equal to {min_val}."
            )
            lines.append(f"        if {param_name} < {min_val}:")
            lines.append(f"            raise ValueError(")
            lines.append(f'                "{min_err}"')
            lines.append(f"            )")
        if "max" in validation and validation["max"] is not None:
            max_val = validation["max"]
            max_err = validation.get(
                "max_error", f"The value must be less than or equal to {max_val}."
            )
            lines.append(f"        if {param_name} > {max_val}:")
            lines.append(f"            raise ValueError(")
            lines.append(f'                "{max_err}"')
            lines.append(f"            )")

    # Warnings
    warnings_def = s.get("warnings")
    if warnings_def:
        if "below" in warnings_def and warnings_def["below"] is not None:
            below = warnings_def["below"]
            threshold = below["threshold"]
            msg = below["message"].replace("{value}", f"{{{param_name}}}")
            lines.append(f"        if {param_name} < {threshold}:")
            lines.append(f"            managed_print(")
            lines.append(f'                f"Warning: {msg}"')
            lines.append(f"            )")
        if "above" in warnings_def and warnings_def["above"] is not None:
            above = warnings_def["above"]
            threshold = above["threshold"]
            msg = above["message"].replace("{value}", f"{{{param_name}}}")
            lines.append(f"        if {param_name} > {threshold}:")
            lines.append(f"            managed_print(")
            lines.append(f'                f"Warning: {msg}"')
            lines.append(f"            )")

    # super().__init__
    if validation or warnings_def:
        lines.append(
            f'        super().__init__(key="{s["key"]}", value={param_name})'
        )
    else:
        lines.append("")
        lines.append(
            f'        super().__init__(key="{s["key"]}", value={param_name})'
        )

    lines.append("")
    return "\n".join(lines)


def generate_init_module(settings: list[dict[str, Any]]) -> str:
    lines: list[str] = []
    lines.append(GENERATED_HEADER)

    for s in settings:
        file_name = s["file_name"]
        class_name = s["class_name"]
        lines.append(f"from .{file_name} import {class_name}")

    # Hand-written imports
    lines.append("from .custom_setting import CustomSetting")
    lines.append("from ._rapidata_setting import RapidataSetting")
    lines.append("from .rapidata_settings import RapidataSettings")
    lines.append("")

    return "\n".join(lines)


def generate_rapidata_settings(settings: list[dict[str, Any]]) -> str:
    lines: list[str] = []
    lines.append(GENERATED_HEADER)

    # Imports
    for s in settings:
        file_name = s["file_name"]
        class_name = s["class_name"]
        lines.append(f"from rapidata.rapidata_client.settings.{file_name} import {class_name}")

    lines.append("")
    lines.append("")
    lines.append("class RapidataSettings:")
    lines.append('    """')
    lines.append(
        "    Container class for all setting factory functions"
    )
    lines.append("")
    lines.append(
        "    Settings can be added to an order to determine the behaviour of the task."
    )
    lines.append("")
    lines.append("    Attributes:")

    for s in settings:
        container_name = s["container_name"]
        class_name = s["class_name"]
        short_desc = s["description"].split("\n")[0]
        lines.append(
            f"        {container_name} ({class_name}): {short_desc}"
        )

    lines.append("")
    lines.append("    Example:")
    lines.append("        ```python")
    lines.append("        from rapidata import NoShuffleSetting")
    lines.append("        settings=[NoShuffleSetting()]")
    lines.append("        ```")
    lines.append("")
    lines.append(
        "        This can be used in an order to disable shuffling of categories."
    )
    lines.append('    """')
    lines.append("")

    for s in settings:
        container_name = s["container_name"]
        class_name = s["class_name"]
        lines.append(f"    {container_name} = {class_name}")

    lines.append("")
    return "\n".join(lines)


def write_if_changed(path: Path, content: str, check_mode: bool) -> bool:
    """Write content to path. Returns True if file changed (or would change in check mode)."""
    if path.exists():
        existing = path.read_text(encoding="utf-8")
        if existing == content:
            return False
        # Safety: don't overwrite hand-written files
        if path.name in HANDWRITTEN_FILES:
            print(f"ERROR: Refusing to overwrite hand-written file: {path.name}")
            sys.exit(1)
        if path.exists() and not existing.startswith("# This file is auto-generated"):
            # File exists but isn't marked as generated - check if it's a known file we're replacing
            pass

    if check_mode:
        return True

    path.write_text(content, encoding="utf-8")
    return True


def main():
    check_mode = "--check" in sys.argv
    args = [a for a in sys.argv[1:] if not a.startswith("--")]
    if not args:
        print("Usage: generate_settings.py <path-to-settings.json> [--check]")
        sys.exit(1)
    settings_json = Path(args[0])
    if not settings_json.exists():
        print(f"ERROR: settings.json not found at {settings_json}")
        sys.exit(1)

    settings = load_settings(settings_json)
    changed_files: list[str] = []
    unchanged_files: list[str] = []

    # Generate individual setting modules
    for s in settings:
        content = generate_setting_module(s)
        path = SETTINGS_DIR / f"{s['file_name']}.py"
        if write_if_changed(path, content, check_mode):
            changed_files.append(str(path.relative_to(REPO_ROOT)))
        else:
            unchanged_files.append(str(path.relative_to(REPO_ROOT)))

    # Generate __init__.py
    content = generate_init_module(settings)
    path = SETTINGS_DIR / "__init__.py"
    if write_if_changed(path, content, check_mode):
        changed_files.append(str(path.relative_to(REPO_ROOT)))
    else:
        unchanged_files.append(str(path.relative_to(REPO_ROOT)))

    # Generate rapidata_settings.py
    content = generate_rapidata_settings(settings)
    path = SETTINGS_DIR / "rapidata_settings.py"
    if write_if_changed(path, content, check_mode):
        changed_files.append(str(path.relative_to(REPO_ROOT)))
    else:
        unchanged_files.append(str(path.relative_to(REPO_ROOT)))

    if check_mode:
        if changed_files:
            print("ERROR: Generated files are out of date:")
            for f in changed_files:
                print(f"  {f}")
            print("\nRun 'uv run python scripts/generate_settings.py' to regenerate.")
            sys.exit(1)
        else:
            print("All generated files are up to date.")
            sys.exit(0)
    else:
        if changed_files:
            print(f"Generated {len(changed_files)} file(s):")
            for f in changed_files:
                print(f"  {f}")
        if unchanged_files:
            print(f"Unchanged: {len(unchanged_files)} file(s)")
        print("Done.")


if __name__ == "__main__":
    main()
